mapper.select:
SELECT o.*, pb.serial_number as powerBankSerialNumber, s.name as stationName FROM orders o LEFT JOIN powerbanks pb ON o.powerbank_id = pb.id LEFT JOIN stations s ON o.station_id = s.id
o.user_id = #{userId}
ORDER BY o.create_time DESC

mapper.update:
UPDATE orders
return_time = #{returnTime}, amount = #{amount}, status = #{status},
WHERE id = #{id}
